Complete the getopts loop to handle -v (verbose) and -f (file with argument) flags:

while getopts _____ opt; do
  case $opt in
    v) verbose=true ;;
    f) file="$OPTARG" ;;
    ?) echo "Usage: $0 [-v] [-f file]" >&2; exit 1 ;;
  esac
done

